    body.gain.setValueAtTime(0.0001, t);
    body.gain.exponentialRampToValueAtTime(0.92 * intensity, t + 0.006);
    body.gain.exponentialRampToValueAtTime(0.0001, t + 0.38);
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1400, t);
    filter.frequency.exponentialRampToValueAtTime(180, t + 0.18);

    click.type = 'square';
    click.frequency.setValueAtTime(2200, t);
    clickGain.gain.setValueAtTime(0.18 * intensity, t);
    clickGain.gain.exponentialRampToValueAtTime(0.0001, t + 0.018);

    osc.connect(filter);
    filter.connect(body);
    body.connect(output);
    click.connect(clickGain);
    clickGain.connect(output);
    osc.start(t);
    click.start(t);
    osc.stop(t + 0.42);
    click.stop(t + 0.04);
    track(0.48, osc, body, click, clickGain, filter);
  };

  const playClap = (time, intensity = 1) => {
    const t = safeTime(audio, time);
    for (let i = 0; i < 3; i += 1) {
      const source = audio.createBufferSource();
      const filter = audio.createBiquadFilter();
      const gain = audio.createGain();
      const delay = i * 0.014;
      source.buffer = noiseBuffer;
      filter.type = 'bandpass';
      filter.frequency.setValueAtTime(1380 + i * 180, t + delay);
      filter.Q.setValueAtTime(1.3, t + delay);
      gain.gain.setValueAtTime(0.0001, t + delay);
      gain.gain.exponentialRampToValueAtTime(0.24 * intensity, t + delay + 0.004);
      gain.gain.exponentialRampToValueAtTime(0.0001, t + delay + 0.105);
      source.connect(filter);
      filter.connect(gain);
      gain.connect(output);
      source.start(t + delay);
      source.stop(t + delay + 0.14);
      track(0.2 + delay, source, filter, gain);
    }
  };

  const playHat = (time, intensity = 1, open = false) => {
    const t = safeTime(audio, time);
    const source = audio.createBufferSource();
    const highpass = audio.createBiquadFilter();
    const bandpass = audio.createBiquadFilter();
    const gain = audio.createGain();
    source.buffer = noiseBuffer;
    highpass.type = 'highpass';
    highpass.frequency.setValueAtTime(open ? 5200 : 6800, t);
    bandpass.type = 'bandpass';
    bandpass.frequency.setValueAtTime(open ? 9200 : 7800, t);
    bandpass.Q.setValueAtTime(open ? 0.7 : 1.4, t);
    gain.gain.setValueAtTime(0.0001, t);
    gain.gain.exponentialRampToValueAtTime((open ? 0.14 : 0.095) * intensity * state.hat, t + 0.004);
    gain.gain.exponentialRampToValueAtTime(0.0001, t + (open ? 0.24 : 0.055));
    source.connect(highpass);
    highpass.connect(bandpass);
    bandpass.connect(gain);
    gain.connect(output);
    source.start(t);
    source.stop(t + (open ? 0.3 : 0.08));
    track(open ? 0.34 : 0.12, source, highpass, bandpass, gain);
  };

  const handleClockTick = ({ step, time, duration }) => {
    if (destroyed) return;
    currentStep = modulo(step, 16);
    renderBeat();
    if (!state.enabled) return;

    const stepDuration = Number.isFinite(duration) && duration > 0 ? duration : 0.125;
    const swingOffset = currentStep % 2 === 1 ? stepDuration * state.swing : 0;
    const t = time + swingOffset;

    if (currentStep % 4 === 0) {
      playKick(time, currentStep === 0 || currentStep === 8 ? 1 : 0.9);
      pulse = Math.max(pulse, 1);
    }
    if (currentStep === 4 || currentStep === 12) {
      playClap(t, state.clap);
      pulse = Math.max(pulse, 0.78);
    }
    if (currentStep % 2 === 0) {
      playHat(t, currentStep % 4 === 2 ? 0.88 : 0.58, currentStep % 4 === 2);
      pulse = Math.max(pulse, 0.38);
    } else if (state.hat > 0.45) {
      playHat(t, 0.36, false);
    }
    if ((currentStep === 15 || currentStep === 7) && state.clap > 0.48) {
      playClap(t + stepDuration * 0.47, state.clap * 0.34);
    }
  };

  const sliderHandlers = {
    volume: () => {
      state.volume = clamp(Number(sliders.volume.value), 0, 1);
      syncUi();
    },
    hat: () => {
      state.hat = clamp(Number(sliders.hat.value), 0, 1);
      syncUi();
    },
    clap: () => {
      state.clap = clamp(Number(sliders.clap.value), 0, 1);
      syncUi();
    },
    drive: () => {
      state.drive = clamp(Number(sliders.drive.value), 0, 1);
      syncUi();
    },
    swing: () => {
      state.swing = clamp(Number(sliders.swing.value), 0, 0.28);
      syncUi();
    }
  };

  const onToggle = () => {
    state.enabled = !state.enabled;
    syncUi();
  };

  toggleButton.addEventListener('click', onToggle);
  Object.entries(sliderHandlers).forEach(([key, handler]) => {
    sliders[key].addEventListener('input', handler);
  });
  const unsubscribeClock = ctx.clock.onTick(handleClockTick);
  const animation = setInterval(renderBeat, 60);
  syncUi();
  renderBeat();

  return {
    update() {},
    getState() {
      return {
        stateVersion: state.stateVersion,
        enabled: state.enabled,
        volume: state.volume,
        drive: state.drive,
        hat: state.hat,
        swing: state.swing,
        clap: state.clap
      };
    },
    destroy() {
      destroyed = true;
      clearInterval(animation);
      unsubscribeClock();
      toggleButton.removeEventListener('click', onToggle);
      Object.entries(sliderHandlers).forEach(([key, handler]) => {
        sliders[key].removeEventListener('input', handler);
      });
      cleanupTimers.forEach((timer) => clearTimeout(timer));
      cleanupTimers.clear();
      for (const node of liveNodes) {
        try { if (typeof node.stop === 'function') node.stop(); } catch (_) {}
        try { if (typeof node.disconnect === 'function') node.disconnect(); } catch (_) {}
      }
      liveNodes.clear();
      try {
        output.disconnect();
        drive.disconnect();
        compressor.disconnect();
      } catch (_) {}
    }
  };

  function track(seconds, ...nodes) {
    nodes.forEach((node) => liveNodes.add(node));
    const timer = setTimeout(() => {
      cleanupTimers.delete(timer);
      nodes.forEach((node) => {
        try { if (typeof node.disconnect === 'function') node.disconnect(); } catch (_) {}
        liveNodes.delete(node);
      });
    }, Math.max(80, seconds * 1000 + 140));
    cleanupTimers.add(timer);
  }
}

function createNoiseBuffer(audio, seconds) {
  const length = Math.max(1, Math.floor(audio.sampleRate * seconds));
  const buffer = audio.createBuffer(1, length, audio.sampleRate);
  const data = buffer.getChannelData(0);
  let previous = 0;
  for (let i = 0; i < length; i += 1) {
    const white = Math.random() * 2 - 1;
    previous = white * 0.74 + previous * 0.26;
    data[i] = previous;
  }
  return buffer;
}

function makeDriveCurve(amount) {
  const curve = new Float32Array(512);
  for (let i = 0; i < curve.length; i += 1) {
    const x = (i / (curve.length - 1)) * 2 - 1;
    curve[i] = Math.tanh(x * amount);
  }
  return curve;
}

function safeTime(audio, time) {
  return Math.max(Number.isFinite(time) ? time : audio.currentTime, audio.currentTime + 0.001);
}

function modulo(value, size) {
  return ((value % size) + size) % size;
}

function finite(value, fallback) {
  return Number.isFinite(value) ? value : fallback;
}

function clamp(value, min, max) {
  if (!Number.isFinite(value)) return min;
  return Math.min(max, Math.max(min, value));
}
